VALUES
  (@city_macau_id, @sub_map_macau_peninsula_id, @storyline_macau_fire_id, 'ama_temple', '妈阁庙', 'A-Ma Temple', '媽閣廟', 'Templo de A-Ma', '初战海岸', 'First shoreline clash', '初戰海岸', 'Primeira linha de confronto', '妈阁庙前地', 'Largo do Pagode da Barra', '媽閣廟前地', 'Largo do Pagode da Barra', 'GCJ02', 22.1868400, 113.5315900, 'macau', 22.1868400, 113.5315900, 60, 120, 40, 'temple', 'medium', '澳门半岛', 'Macau Peninsula', '澳門半島', 'Peninsula de Macau', 300003, 300008, '海风、香火与海防记忆在这里交叠，路线从最早的海岸对峙开始。', 'The route opens where incense, sea wind, and coastal defense memory overlap.', '海風、香火與海防記憶在這裡交疊，路線從最早的海岸對峙開始。', 'A rota abre onde incenso, vento do mar e defesa costeira se encontram.', '镜海初战', 'First Clash Across the Mirror Sea', '鏡海初戰', 'Primeiro confronto na enseada', '靠近妈阁庙时会触发开场剧情与古战场音景。', 'Approaching A-Ma triggers the opening scene and a shoreline soundscape.', '靠近媽閣廟時會觸發開場劇情與古戰場音景。', 'Ao aproximar-se de A-Ma, surge a cena de abertura e uma paisagem sonora antiga.', JSON_OBJECT('enabled', TRUE, 'mode', 'sheet', 'headline', '镜海初战'), JSON_OBJECT('showIntroPopup', TRUE, 'displayMode', 'story-card'), 'published', 1, NOW(), @seed_openid),
  (@city_macau_id, @sub_map_macau_peninsula_id, @storyline_macau_fire_id, 'lilau_square', '亚婆井前地', 'Lilau Square', '亞婆井前地', 'Largo do Lilau', '南湾界线', 'Boundary at the inner bay', '南灣界線', 'Linha da fronteira', '亚婆井前地', 'Largo do Lilau', '亞婆井前地', 'Largo do Lilau', 'GCJ02', 22.1852450, 113.5373910, 'macau', 22.1852450, 113.5373910, 55, 110, 35, 'historic-square', 'easy', '澳门半岛', 'Macau Peninsula', '澳門半島', 'Peninsula de Macau', 300004, 300008, '井、水、石墙与旧地图让边界被看见，也让拉锯成为故事核心。', 'Water, stone walls, and old maps make the boundary line visible here.', '井、水、石牆與舊地圖讓邊界被看見，也讓拉鋸成為故事核心。', 'Agua, muros e mapas antigos tornam visivel a fronteira silenciosa.', '南湾防线', 'The Southern Boundary Line', '南灣防線', 'A linha do sul', '停留与互动会解锁界线资料与下一章线索。', 'Staying and interacting here unlocks boundary material and the next clue.', '停留與互動會解鎖界線資料與下一章線索。', 'Ficar e interagir aqui desbloqueia material da fronteira e a pista seguinte.', JSON_OBJECT('enabled', TRUE, 'mode', 'sheet', 'headline', '南湾防线'), JSON_OBJECT('showIntroPopup', TRUE, 'displayMode', 'story-card'), 'published', 2, NOW(), @seed_openid),
  (@city_macau_id, @sub_map_macau_peninsula_id, @storyline_macau_fire_id, 'dom_pedro_v_theatre', '岗顶剧院', 'Dom Pedro V Theatre', '崗頂劇院', 'Teatro Dom Pedro V', '山城瞭望', 'Hilltop watchline', '山城瞭望', 'Vigia da colina', '岗顶前地', 'Largo de Santo Agostinho', '崗頂前地', 'Largo de Santo Agostinho', 'GCJ02', 22.1913260, 113.5404180, 'macau', 22.1913260, 113.5404180, 60, 120, 45, 'lookout', 'medium', '澳门半岛', 'Macau Peninsula', '澳門半島', 'Peninsula de Macau', 300005, 300008, '山城高地把剧院、修院与瞭望线叠在一起，形成新的紧张感。', 'The hill district layers theatre, mission, and lookout logic into one elevated scene.', '山城高地把劇院、修院與瞭望線疊在一起，形成新的緊張感。', 'A colina combina teatro, missao e vigia numa mesma cena elevada.', '山城戒备', 'Watch from the Hill', '山城戒備', 'Vigia na colina', '这里会开启瞭望点对照内容，夜间还能触发暗哨音景。', 'This stop opens the lookout comparison and an optional night audio vignette.', '這裡會開啟瞭望點對照內容，夜間還能觸發暗哨音景。', 'Aqui abre-se a comparacao da vigia e um audio noturno opcional.', JSON_OBJECT('enabled', TRUE, 'mode', 'sheet', 'headline', '山城戒备'), JSON_OBJECT('showIntroPopup', TRUE, 'displayMode', 'story-card'), 'published', 3, NOW(), @seed_openid),
  (@city_macau_id, @sub_map_macau_peninsula_id, @storyline_macau_fire_id, 'monte_fort', '大炮台', 'Monte Fort', '大炮台', 'Fortaleza do Monte', '炮台反击', 'Fortress counterfire', '炮台反擊', 'Contra-ataque da fortaleza', '大炮台街', 'Calcada das Verdades', '大炮台街', 'Calcada das Verdades', 'GCJ02', 22.1974760, 113.5407570, 'macau', 22.1974760, 113.5407570, 70, 140, 45, 'fortress', 'hard', '澳门半岛', 'Macau Peninsula', '澳門半島', 'Peninsula de Macau', 300006, 300008, '城墙、炮位与海面把一六二二年的战役重新拉回玩家眼前。', 'Walls, batteries, and the harbor bring the 1622 battle back into view.', '城牆、炮位與海面把一六二二年的戰役重新拉回玩家眼前。', 'Muralhas, baterias e mar devolvem a batalha de 1622 ao presente.', '炮台硝烟', 'Cannons Over the Harbor', '炮台硝煙', 'Canhoes sobre a enseada', '双炮位互动会触发战役回放，让第四章到达高潮。', 'A dual-battery interaction unlocks the battle recap and the route climax.', '雙炮位互動會觸發戰役回放，讓第四章到達高潮。', 'A interacao com duas baterias desbloqueia o resumo da batalha e o auge da rota.', JSON_OBJECT('enabled', TRUE, 'mode', 'sheet', 'headline', '炮台硝烟'), JSON_OBJECT('showIntroPopup', TRUE, 'displayMode', 'story-card'), 'published', 4, NOW(), @seed_openid),
  (@city_macau_id, @sub_map_macau_peninsula_id, @storyline_macau_fire_id, 'senado_square', '议事亭前地', 'Senado Square', '議事亭前地', 'Largo do Senado', '战后共生', 'Coexistence after the smoke', '戰後共生', 'Convivencia depois da fumaca', '议事亭前地', 'Largo do Senado', '議事亭前地', 'Largo do Senado', 'GCJ02', 22.1934650, 113.5392280, 'macau', 22.1934650, 113.5392280, 55, 120, 30, 'civic-square', 'easy', '澳门半岛', 'Macau Peninsula', '澳門半島', 'Peninsula de Macau', 300007, 300008, '终章把战火与边界收回到今日澳门的公共生活与共享节奏。', 'The finale resolves conflict and vigilance into present-day civic rhythm.', '終章把戰火與邊界收回到今日澳門的公共生活與共享節奏。', 'O final transforma guerra e fronteira em convivio urbano partilhado.', '烽烟落幕', 'The City After Smoke', '烽煙落幕', 'A cidade depois da fumaca', '这里会回顾全线并解锁最终奖励与分享海报。', 'This stop reviews the whole route and unlocks the final rewards.', '這裡會回顧全線並解鎖最終獎勵與分享海報。', 'Aqui a rota recapitula tudo e desbloqueia as recompensas finais.', JSON_OBJECT('enabled', TRUE, 'mode', 'sheet', 'headline', '烽烟落幕'), JSON_OBJECT('showIntroPopup', TRUE, 'displayMode', 'story-card'), 'published', 5, NOW(), @seed_openid);

SET @poi_ama_temple_id = (SELECT `id` FROM `pois` WHERE `code` = 'ama_temple' ORDER BY `id` DESC LIMIT 1);
SET @poi_lilau_square_id = (SELECT `id` FROM `pois` WHERE `code` = 'lilau_square' ORDER BY `id` DESC LIMIT 1);
SET @poi_dom_pedro_v_theatre_id = (SELECT `id` FROM `pois` WHERE `code` = 'dom_pedro_v_theatre' ORDER BY `id` DESC LIMIT 1);
SET @poi_monte_fort_id = (SELECT `id` FROM `pois` WHERE `code` = 'monte_fort' ORDER BY `id` DESC LIMIT 1);
SET @poi_senado_square_id = (SELECT `id` FROM `pois` WHERE `code` = 'senado_square' ORDER BY `id` DESC LIMIT 1);

