VALUES
  (311001, @storyline_macau_fire_id, 1, '第一章 镜海初战', 'Chapter 1: First Clash Across the Mirror Sea', '第一章 鏡海初戰', 'Capitulo 1: Primeiro confronto na enseada', '在妈阁庙回到澳门最早的海岸对峙。', 'Return to the earliest coastal confrontation at A-Ma Temple.', '在媽閣廟回到澳門最早的海岸對峙。', 'Regressa ao primeiro confronto costeiro em A-Ma.', '这一章用海风、香火与炮声打开路线，让玩家先看见澳门如何在海岸边界上开始讲述自己。', 'The route opens with sea wind, incense, and artillery memory to frame Macau at its first shoreline edge.', '這一章用海風、香火與炮聲打開路線，讓玩家先看見澳門如何在海岸邊界上開始講述自己。', 'O capitulo abre a rota com vento do mar, incenso e memoria de canhoes.', '解锁收集物“初见濠江”，并开启下一站。', 'Unlock the collectible "First Sight of Macau" and open the next stop.', '解鎖收集物「初見濠江」，並開啟下一站。', 'Desbloqueia o colecionavel "Primeira visao de Macau" e abre a etapa seguinte.', '初见濠江', 'First Sight of Macau', '初見濠江', 'Primeira visao de Macau', '妈阁庙', 'A-Ma Temple', '媽閣廟', 'Templo de A-Ma', 300003, 'poi', @poi_ama_temple_id, 'ama_temple', 'proximity', JSON_OBJECT('distanceMeters', 50, 'poiCode', 'ama_temple'), JSON_OBJECT('triggers', JSON_ARRAY(JSON_OBJECT('type', 'proximity', 'poiCode', 'ama_temple', 'distanceMeters', 50))), JSON_OBJECT('steps', JSON_ARRAY(JSON_OBJECT('type', 'read_story'), JSON_OBJECT('type', 'view_overlay', 'overlayCode', 'ming-warship')), 'unlockNextChapter', TRUE), JSON_OBJECT('collectibleCodes', JSON_ARRAY('collectible_first_sight_macau'), 'badgeCodes', JSON_ARRAY(), 'rewardCodes', JSON_ARRAY()), 'published', 1, NOW(), @seed_openid),
  (311002, @storyline_macau_fire_id, 2, '第二章 南湾防线', 'Chapter 2: The Southern Boundary Line', '第二章 南灣防線', 'Capitulo 2: A linha do sul', '在亚婆井前地看见安静却持久的边界。', 'See a quiet but lasting boundary at Lilau Square.', '在亞婆井前地看見安靜卻持久的邊界。', 'Ve a fronteira silenciosa e duradoura em Lilau.', '第二章让旧井、石墙与边界资料成为主角，让玩家理解澳门也曾在安静处承受最久的拉锯。', 'Old wells, walls, and boundary records become the main actors in this quieter chapter.', '第二章讓舊井、石牆與邊界資料成為主角，讓玩家理解澳門也曾在安靜處承受最久的拉鋸。', 'Poços, muros e arquivos tornam-se protagonistas deste capitulo mais silencioso.', '解锁“界线守护者”徽章条件，并推进下一章。', 'Unlock the badge path for "Keeper of the Boundary".', '解鎖「界線守護者」徽章條件，並推進下一章。', 'Desbloqueia o caminho da insignia "Guardiao da Fronteira".', '界线守护者', 'Keeper of the Boundary', '界線守護者', 'Guardiao da Fronteira', '亚婆井前地', 'Lilau Square', '亞婆井前地', 'Largo do Lilau', 300004, 'poi', @poi_lilau_square_id, 'lilau_square', 'sequence', JSON_OBJECT('requiresChapterOrder', 1), JSON_OBJECT('requiresChapterIds', JSON_ARRAY(311001)), JSON_OBJECT('steps', JSON_ARRAY(JSON_OBJECT('type', 'interact_overlay', 'overlayCode', 'old-boundary-marker'), JSON_OBJECT('type', 'stay_seconds', 'seconds', 10)), 'unlockNextChapter', TRUE), JSON_OBJECT('collectibleCodes', JSON_ARRAY('collectible_boundary_map_fragment'), 'badgeCodes', JSON_ARRAY('badge_boundary_keeper'), 'rewardCodes', JSON_ARRAY()), 'published', 2, NOW(), @seed_openid),
  (311003, @storyline_macau_fire_id, 3, '第三章 山城戒备', 'Chapter 3: Watch from the Hill', '第三章 山城戒備', 'Capitulo 3: Vigia na colina', '岗顶把宗教、教育与瞭望线叠成新的张力。', 'The hill district layers faith, culture, and lookout lines.', '崗頂把宗教、教育與瞭望線疊成新的張力。', 'A colina junta fe, cultura e vigia numa nova tensao.', '第三章把路线带上高处，让玩家从钟声、坡道与视线控制中看见澳门山城的隐性防线。', 'The route climbs uphill to reveal how the district watched both harbor and city.', '第三章把路線帶上高處，讓玩家從鐘聲、坡道與視線控制中看見澳門山城的隱性防線。', 'A rota sobe e mostra como a colina vigiava porto e cidade ao mesmo tempo.', '获得“山城瞭望者”观察札记，并解锁炮台高潮。', 'Gain the "Hill Watcher" log and unlock the fortress climax.', '獲得「山城瞭望者」觀察札記，並解鎖炮台高潮。', 'Recebe o caderno "Vigia da Colina" e desbloqueia o auge na fortaleza.', '山城瞭望者', 'Hill Watcher', '山城瞭望者', 'Vigia da Colina', '岗顶剧院', 'Dom Pedro V Theatre', '崗頂劇院', 'Teatro Dom Pedro V', 300005, 'poi', @poi_dom_pedro_v_theatre_id, 'dom_pedro_v_theatre', 'sequence', JSON_OBJECT('requiresChapterOrder', 2), JSON_OBJECT('requiresChapterIds', JSON_ARRAY(311001, 311002)), JSON_OBJECT('steps', JSON_ARRAY(JSON_OBJECT('type', 'view_overlay', 'overlayCode', 'hill-watchpoint'), JSON_OBJECT('type', 'time_window', 'segment', 'night', 'optional', TRUE)), 'unlockNextChapter', TRUE), JSON_OBJECT('collectibleCodes', JSON_ARRAY('collectible_hill_watch_log'), 'badgeCodes', JSON_ARRAY(), 'rewardCodes', JSON_ARRAY()), 'published', 3, NOW(), @seed_openid),
  (311004, @storyline_macau_fire_id, 4, '第四章 炮台硝烟', 'Chapter 4: Cannons Over the Harbor', '第四章 炮台硝煙', 'Capitulo 4: Canhoes sobre a enseada', '大炮台把一六二二年的炮火重新推回眼前。', 'Monte Fort pulls the 1622 cannon line back into the present.', '大炮台把一六二二年的炮火重新推回眼前。', 'A Fortaleza devolve os canhoes de 1622 ao presente.', '这一章是整条路线的高潮，城墙、炮位与海面重新对齐，让玩家直观看见守城与反击。', 'Walls, batteries, and the harbor align again to make the battle legible and immediate.', '這一章是整條路線的高潮，城牆、炮位與海面重新對齊，讓玩家直觀看見守城與反擊。', 'Este capitulo e o auge da rota, com muralhas, baterias e mar alinhados diante do utilizador.', '解锁“要塞英雄”徽章，并打开终章回顾。', 'Unlock the badge "Fortress Hero" and open the finale.', '解鎖「要塞英雄」徽章，並打開終章回顧。', 'Desbloqueia a insignia "Heroi da Fortaleza" e abre o final.', '要塞英雄', 'Fortress Hero', '要塞英雄', 'Heroi da Fortaleza', '大炮台', 'Monte Fort', '大炮台', 'Fortaleza do Monte', 300006, 'poi', @poi_monte_fort_id, 'monte_fort', 'sequence', JSON_OBJECT('requiresChapterOrder', 3), JSON_OBJECT('requiresChapterIds', JSON_ARRAY(311001, 311002, 311003)), JSON_OBJECT('steps', JSON_ARRAY(JSON_OBJECT('type', 'interact_overlay', 'overlayCode', 'cannon-fire'), JSON_OBJECT('type', 'visit_waypoints', 'count', 2, 'waypointCodes', JSON_ARRAY('fort-north-battery', 'fort-east-wall'))), 'unlockNextChapter', TRUE), JSON_OBJECT('collectibleCodes', JSON_ARRAY(), 'badgeCodes', JSON_ARRAY('badge_fortress_hero'), 'rewardCodes', JSON_ARRAY()), 'published', 4, NOW(), @seed_openid),
  (311005, @storyline_macau_fire_id, 5, '第五章 烽烟落幕', 'Chapter 5: The City After Smoke', '第五章 烽煙落幕', 'Capitulo 5: A cidade depois da fumaca', '议事亭前地让路线回到今日澳门的公共生活。', 'Senado Square resolves the route into present-day civic life.', '議事亭前地讓路線回到今日澳門的公共生活。', 'O Largo do Senado fecha a rota na vida publica atual de Macau.', '终章用步行声、广场与共享节奏收回前面几章的硝烟，并把整条路线变成档案与语音奖励。', 'The finale answers smoke with public space and turns the walk into archive and voice rewards.', '終章用步行聲、廣場與共享節奏收回前面幾章的硝煙，並把整條路線變成檔案與語音獎勵。', 'O final responde ao fumo com espaco publico e transforma a caminhada em arquivo e recompensa de voz.', '解锁“濠江通史档案”与 AI 战争主题语音包。', 'Unlock the route archive and the war-theme AI voice pack.', '解鎖「濠江通史檔案」與 AI 戰爭主題語音包。', 'Desbloqueia o arquivo da rota e o pacote de voz tematico.', '濠江通史档案', 'Macau Historical Archive', '濠江通史檔案', 'Arquivo Historico de Macau', '议事亭前地', 'Senado Square', '議事亭前地', 'Largo do Senado', 300007, 'poi', @poi_senado_square_id, 'senado_square', 'sequence', JSON_OBJECT('requiresChapterOrder', 4), JSON_OBJECT('requiresChapterIds', JSON_ARRAY(311001, 311002, 311003, 311004)), JSON_OBJECT('steps', JSON_ARRAY(JSON_OBJECT('type', 'auto_play_recap'), JSON_OBJECT('type', 'generate_share_poster')), 'unlockNextChapter', FALSE), JSON_OBJECT('collectibleCodes', JSON_ARRAY(), 'badgeCodes', JSON_ARRAY(), 'rewardCodes', JSON_ARRAY('reward_historic_archive', 'reward_war_voice_pack')), 'published', 5, NOW(), @seed_openid);

SET FOREIGN_KEY_CHECKS = 1;
